version ： git master  2022/5/7
demo：
```
module twocounter( din,row_idx, row_found);
  input din;
  output [1:0]row_idx;
  output row_found; 
  reg [3:0] din;
  reg [3:0] wide_din;
  reg row_found;
  reg [1:0]row_idx;

always_comb
begin : pricen_2d
	integer x;
	wide_din = {4{1'b0}};
	wide_din[3:0] = din;

	row_idx = {2{1'b0}};
	row_found = 1'b0;
	for (x = 0; $unsigned(x) < 4; x=x+1)
	begin
		row_idx = !row_found?x[1:0] : row_idx;
		row_found = !row_found?wide_din[x]:row_found;
	end
end
endmodule
```

